Add selector for location-focused media (after mediaForView, ~line 155):
export function mediaAtLocation(media: MediaItem[], loc: { lat: number; lng: number }): MediaItem[] {
  const threshold = 0.5; // km tolerance
  const liveItems = liveMedia(media);
  return liveItems.filter(m => {
    if (!m.location) return false;
    const dist = haversineDistance(m.location.lat, m.location.lng, loc.lat, loc.lng);
    return dist <= threshold;
  });
}
Or simpler: return liveItems.filter(m => m.location && Math.abs(m.location.lat - loc.lat) < 0.01 && Math.abs(m.location.lng - loc.lng) < 0.01);

(NEW FILE, optional) Haversine distance utility:
export function haversineDistance(lat1: number, lng1: number, lat2: number, lng2: number): number {
  const R = 6371; // Earth radius in km
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180) * Math.cos(lat2*Math.PI/180) * Math.sin(dLng/2)**2;
  return R * 2 * Math.asin(Math.sqrt(a));
}

